# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

using Microsoft.EntityFrameworkCore;

public async Task PurchaseTicketsAsync(int eventId, int quantity)
{
    var tickets = await _context.Tickets
        .Where(t => t.EventId == eventId && t.Quantity > 0)
        .OrderByDescending(t => t.UpdatedAt)
        .FirstOrDefaultAsync();

    if (tickets == null || quantity > tickets.Quantity)
    {
        throw new InvalidOperationException("Not enough available seats.");
    }

    // Check for concurrent updates using the row version/timestamp column
    if (tickets.RowVersion != await _context.Entry(tickets).Reload().RefreshNodeAsync())
    {
        throw new OptimisticConcurrencyException();
    }

    tickets.Quantity -= quantity;
    tickets.PurchasedQuantity += quantity;
    tickets.UpdatedAt = DateTime.UtcNow;
    tickets.RowVersion++;

    await _context.SaveChangesAsync();
}